import{c as t,Q as s,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Permission 細粒度設定","description":"","frontmatter":{},"headers":[],"relativePath":"resources/best-practices/permissions.md","filePath":"resources/best-practices/permissions.md","lastUpdated":1779796674000}'),d={name:"resources/best-practices/permissions.md"};function i(n,e,c,r,l,h){return s(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="permission-細粒度設定" tabindex="-1">Permission 細粒度設定 <a class="header-anchor" href="#permission-細粒度設定" aria-label="Permalink to &quot;Permission 細粒度設定&quot;">​</a></h1><p>Claude Code 使用分層 permission 系統平衡能力與安全。理解這個系統是設計有效 harness 的基礎。</p><h2 id="系統架構" tabindex="-1">系統架構 <a class="header-anchor" href="#系統架構" aria-label="Permalink to &quot;系統架構&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具類型</th><th>範例</th><th>需要核准？</th><th>&quot;Yes, don&#39;t ask again&quot; 行為</th></tr></thead><tbody><tr><td>Read-only</td><td>File reads, Grep</td><td>否</td><td>N/A</td></tr><tr><td>Bash 指令</td><td>Shell execution</td><td>是</td><td>永久（per project directory + command）</td></tr><tr><td>File modification</td><td>Edit/write files</td><td>是</td><td>到 session 結束為止</td></tr></tbody></table><p><strong>規則評估順序</strong>：<code>deny → ask → allow</code>，第一個匹配的規則勝出。deny 規則永遠優先。</p><hr><h2 id="五種-permission-模式" tabindex="-1">五種 Permission 模式 <a class="header-anchor" href="#五種-permission-模式" aria-label="Permalink to &quot;五種 Permission 模式&quot;">​</a></h2><p>透過 <code>settings.json</code> 的 <code>defaultMode</code> 設定：</p><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td><code>default</code></td><td>標準模式：每個工具首次使用時提示</td></tr><tr><td><code>acceptEdits</code></td><td>自動接受 file edits 和常見 filesystem 指令（<code>mkdir</code>, <code>touch</code>, <code>mv</code>, <code>cp</code>）</td></tr><tr><td><code>plan</code></td><td>Plan Mode：Claude 只能分析，不能修改檔案或執行指令</td></tr><tr><td><code>auto</code></td><td>自動核准工具呼叫，含背景安全檢查（Research Preview）</td></tr><tr><td><code>dontAsk</code></td><td>自動拒絕工具，除非透過 <code>/permissions</code> 或 <code>allow</code> 規則預先核准</td></tr><tr><td><code>bypassPermissions</code></td><td>跳過所有 permission prompt（僅限隔離環境）</td></tr></tbody></table><blockquote><p><strong><code>bypassPermissions</code> 警告</strong>：跳過所有 prompt，包含對 <code>.git</code>、<code>.claude</code>、<code>.vscode</code>、<code>.idea</code>、<code>.husky</code> 的寫入。僅限 container/VM 隔離環境使用。</p></blockquote><hr><h2 id="規則語法" tabindex="-1">規則語法 <a class="header-anchor" href="#規則語法" aria-label="Permalink to &quot;規則語法&quot;">​</a></h2><p>格式：<code>Tool</code> 或 <code>Tool(specifier)</code></p><h3 id="wildcard-模式" tabindex="-1">Wildcard 模式 <a class="header-anchor" href="#wildcard-模式" aria-label="Permalink to &quot;Wildcard 模式&quot;">​</a></h3><p>Bash 規則支援 <code>*</code> glob pattern，可出現在指令任何位置：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(npm run *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git commit *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git * main)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(* --version)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(* --help *)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(git push *)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>重要細節</strong>：</p><ul><li><code>Bash(ls *)</code> 匹配 <code>ls -la</code> 但<strong>不匹配</strong> <code>lsof</code>（空格前有 word boundary）</li><li><code>Bash(ls*)</code> 匹配 <code>ls -la</code> 和 <code>lsof</code>（無 word boundary）</li><li><code>:*</code> 後綴等同 trailing wildcard：<code>Bash(ls:*)</code> 和 <code>Bash(ls *)</code> 等效</li><li>單個 <code>*</code> 跨越多個 argument：<code>Bash(git *)</code> 匹配 <code>git log --oneline --all</code></li></ul><hr><h2 id="bash-規則詳解" tabindex="-1">Bash 規則詳解 <a class="header-anchor" href="#bash-規則詳解" aria-label="Permalink to &quot;Bash 規則詳解&quot;">​</a></h2><h3 id="複合指令-compound-commands" tabindex="-1">複合指令（Compound Commands） <a class="header-anchor" href="#複合指令-compound-commands" aria-label="Permalink to &quot;複合指令（Compound Commands）&quot;">​</a></h3><p>Claude Code 能識別 shell operator，<code>Bash(safe-cmd *)</code> <strong>不會</strong>授權 <code>safe-cmd &amp;&amp; other-cmd</code>。</p><p>識別的 separator：<code>&amp;&amp;</code>、<code>||</code>、<code>;</code>、<code>|</code>、<code>|&amp;</code>、<code>&amp;</code>、newlines。規則必須對每個 sub-command 獨立匹配。</p><h3 id="process-wrappers-自動剝離" tabindex="-1">Process Wrappers 自動剝離 <a class="header-anchor" href="#process-wrappers-自動剝離" aria-label="Permalink to &quot;Process Wrappers 自動剝離&quot;">​</a></h3><p>以下 wrapper 在匹配前自動剝離，讓 <code>Bash(npm test *)</code> 也能匹配 <code>timeout 30 npm test</code>：</p><p><code>timeout</code>、<code>time</code>、<code>nice</code>、<code>nohup</code>、<code>stdbuf</code>、bare <code>xargs</code>（無 flag 時）</p><p><strong>不剝離</strong>：<code>direnv exec</code>、<code>devbox run</code>、<code>mise exec</code>、<code>npx</code>、<code>docker exec</code>（需寫含 wrapper 的完整規則）。</p><p><code>watch</code>、<code>setsid</code>、<code>ionice</code>、<code>flock</code> 永遠需要 prompt，<strong>無法</strong>用前綴規則自動核准。</p><p><code>find -exec/-delete</code> 也永遠 prompt，<code>Bash(find *)</code> 不涵蓋這些形式。</p><h3 id="內建唯讀指令-免-prompt" tabindex="-1">內建唯讀指令（免 prompt） <a class="header-anchor" href="#內建唯讀指令-免-prompt" aria-label="Permalink to &quot;內建唯讀指令（免 prompt）&quot;">​</a></h3><p>Claude Code 內建白名單，以下指令永遠免 prompt：</p><p><code>ls</code>、<code>cat</code>、<code>head</code>、<code>tail</code>、<code>grep</code>、<code>find</code>、<code>wc</code>、<code>diff</code>、<code>stat</code>、<code>du</code>、<code>cd</code>，以及 git 的唯讀形式。</p><blockquote><p>此白名單不可設定；如需強制 prompt，加 <code>ask</code> 或 <code>deny</code> 規則。</p></blockquote><h3 id="url-過濾警告" tabindex="-1">URL 過濾警告 <a class="header-anchor" href="#url-過濾警告" aria-label="Permalink to &quot;URL 過濾警告&quot;">​</a></h3><p><code>Bash(curl http://github.com/ *)</code> 等 URL 過濾<strong>脆弱且不可靠</strong>，容易被繞過：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 以下變化均不會匹配：</span></span>
<span class="line"><span>curl -X GET http://github.com/...      # option 在 URL 前</span></span>
<span class="line"><span>curl https://github.com/...            # 不同 protocol</span></span>
<span class="line"><span>curl -L http://bit.ly/xyz              # redirect 到 github</span></span></code></pre></div><p><strong>替代方案</strong>：</p><ul><li>用 <code>deny</code> 封鎖 <code>curl</code>/<code>wget</code>，改用 <code>WebFetch(domain:github.com)</code> 管控</li><li>用 <code>PreToolUse hook</code> 驗證 URL</li></ul><hr><h2 id="read-與-edit-規則" tabindex="-1">Read 與 Edit 規則 <a class="header-anchor" href="#read-與-edit-規則" aria-label="Permalink to &quot;Read 與 Edit 規則&quot;">​</a></h2><h3 id="路徑前綴規則-gitignore-規格" tabindex="-1">路徑前綴規則（gitignore 規格） <a class="header-anchor" href="#路徑前綴規則-gitignore-規格" aria-label="Permalink to &quot;路徑前綴規則（gitignore 規格）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>前綴</th><th>意義</th><th>範例</th><th>解析結果</th></tr></thead><tbody><tr><td><code>//path</code></td><td>絕對路徑（從 filesystem root）</td><td><code>Read(//Users/alice/secrets/**)</code></td><td><code>/Users/alice/secrets/**</code></td></tr><tr><td><code>~/path</code></td><td>從 home directory</td><td><code>Read(~/Documents/*.pdf)</code></td><td><code>/Users/alice/Documents/*.pdf</code></td></tr><tr><td><code>/path</code></td><td>相對於 project root</td><td><code>Edit(/src/**/*.ts)</code></td><td><code>&lt;project root&gt;/src/**/*.ts</code></td></tr><tr><td><code>path</code> 或 <code>./path</code></td><td>相對於當前目錄</td><td><code>Read(*.env)</code></td><td><code>&lt;cwd&gt;/*.env</code></td></tr></tbody></table><blockquote><p><strong>警告</strong>：<code>/Users/alice/file</code> <strong>不是</strong>絕對路徑，是相對於 project root。絕對路徑用 <code>//Users/alice/file</code>。</p></blockquote><h3 id="glob-pattern" tabindex="-1">Glob pattern <a class="header-anchor" href="#glob-pattern" aria-label="Permalink to &quot;Glob pattern&quot;">​</a></h3><ul><li><code>*</code>：匹配單一目錄內的檔案</li><li><code>**</code>：遞迴跨目錄匹配</li></ul><h3 id="symlink-處理" tabindex="-1">Symlink 處理 <a class="header-anchor" href="#symlink-處理" aria-label="Permalink to &quot;Symlink 處理&quot;">​</a></h3><ul><li><strong>Allow 規則</strong>：symlink 本身和目標<strong>都必須</strong>匹配才放行，只匹配一個則 fallback 到提示</li><li><strong>Deny 規則</strong>：symlink 或目標任一匹配就封鎖</li></ul><blockquote><p><strong>重要</strong>：Read/Edit deny 規則只影響 Claude 的內建 file tools，<strong>不影響</strong> Bash subprocess（<code>cat .env</code> 不受 <code>Read(./.env)</code> deny 規則限制）。如需 OS 層強制，啟用 sandbox。</p></blockquote><hr><h2 id="各工具規則" tabindex="-1">各工具規則 <a class="header-anchor" href="#各工具規則" aria-label="Permalink to &quot;各工具規則&quot;">​</a></h2><h3 id="webfetch-規則" tabindex="-1">WebFetch 規則 <a class="header-anchor" href="#webfetch-規則" aria-label="Permalink to &quot;WebFetch 規則&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WebFetch(domain:example.com)&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 匹配對 example.com 的所有請求</span></span></code></pre></div><h3 id="mcp-規則" tabindex="-1">MCP 規則 <a class="header-anchor" href="#mcp-規則" aria-label="Permalink to &quot;MCP 規則&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mcp__puppeteer&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       // 匹配 puppeteer server 的所有工具</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mcp__puppeteer__puppeteer_navigate&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 只匹配特定工具</span></span></code></pre></div><h3 id="subagent-規則" tabindex="-1">Subagent 規則 <a class="header-anchor" href="#subagent-規則" aria-label="Permalink to &quot;Subagent 規則&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Agent(Explore)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 停用 Explore agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h2 id="permission-與-sandbox-的互補關係" tabindex="-1">Permission 與 Sandbox 的互補關係 <a class="header-anchor" href="#permission-與-sandbox-的互補關係" aria-label="Permalink to &quot;Permission 與 Sandbox 的互補關係&quot;">​</a></h2><table tabindex="0"><thead><tr><th>層次</th><th>範圍</th><th>工具</th></tr></thead><tbody><tr><td><strong>Permissions</strong></td><td>控制 Claude Code 可使用哪些工具、存取哪些檔案或域名</td><td>Bash、Read、Edit、WebFetch、MCP 等所有工具</td></tr><tr><td><strong>Sandboxing</strong></td><td>OS 層強制限制 Bash 工具的 filesystem 和 network 存取</td><td>只限 Bash 指令及其子程序</td></tr></tbody></table><p>啟用 sandbox 且 <code>autoAllowBashIfSandboxed: true</code>（預設值）時，sandbox 內的 Bash 無需 prompt。但 explicit deny 規則仍生效，<code>rm</code>/<code>rmdir</code> 指向根目錄等高危路徑仍會提示。</p><hr><h2 id="managed-settings-組織-policy" tabindex="-1">Managed Settings（組織 Policy） <a class="header-anchor" href="#managed-settings-組織-policy" aria-label="Permalink to &quot;Managed Settings（組織 Policy）&quot;">​</a></h2><p>管理員可部署無法被 user/project settings 覆蓋的 managed settings：</p><table tabindex="0"><thead><tr><th>設定</th><th>說明</th></tr></thead><tbody><tr><td><code>allowManagedHooksOnly</code></td><td><code>true</code> 時只載入 managed hooks，封鎖其他所有 hook</td></tr><tr><td><code>allowManagedMcpServersOnly</code></td><td><code>true</code> 時只允許 managed settings 的 MCP server</td></tr><tr><td><code>allowManagedPermissionRulesOnly</code></td><td><code>true</code> 時禁止 user/project settings 定義 allow/ask/deny 規則</td></tr><tr><td><code>sandbox.network.allowManagedDomainsOnly</code></td><td>只允許 managed 的 allowedDomains，非白名單自動封鎖</td></tr></tbody></table><h3 id="settings-優先序" tabindex="-1">Settings 優先序 <a class="header-anchor" href="#settings-優先序" aria-label="Permalink to &quot;Settings 優先序&quot;">​</a></h3><ol><li><strong>Managed settings</strong>（最高，無法被任何層覆蓋）</li><li>Command line arguments（臨時 session override）</li><li>Local project settings（<code>.claude/settings.local.json</code>）</li><li>Shared project settings（<code>.claude/settings.json</code>）</li><li><strong>User settings</strong>（<code>~/.claude/settings.json</code>，最低）</li></ol><blockquote><p>工具在任一層被 deny，其他層都無法 allow。</p></blockquote><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/en/permissions" target="_blank" rel="noreferrer">官方 Permissions 文件</a></li><li><a href="https://code.claude.com/docs/en/sandboxing" target="_blank" rel="noreferrer">Sandboxing 文件</a></li><li><a href="/cc-workspace-docs/resources/best-practices/hooks">Hooks 設計模式</a></li><li><a href="/cc-workspace-docs/lectures/lecture-06-security/">Lecture 06：安全沙箱與 Proxy</a></li></ul>`,70)])])}const k=t(d,[["render",i]]);export{u as __pageData,k as default};
